func DefaultPatchSetSessionLog(ctx context.Context, objects []*SessionLog, updateMasks []*field_mask.FieldMask, db *gorm.DB) ([]*SessionLog, error) {
	if len(objects) != len(updateMasks) {
		return nil, fmt.Errorf(errors.BadRepeatedFieldMaskTpl, len(updateMasks), len(objects))
	}

	results := make([]*SessionLog, 0, len(objects))
	for i, patcher := range objects {
		pbResponse, err := DefaultPatchSessionLog(ctx, patcher, updateMasks[i], db)
		if err != nil {
			return nil, err
		}

		results = append(results, pbResponse)
	}

	return results, nil
}

